fun solve(nums: Array<Long>, k: Long): Long {
    val totalSum = nums.sum()
    var prefixSum = 0L
    val modMap = HashMap<Long, Long>().apply { put(0L, 0L) }
    var dpPrev = 0L
    for (num in nums) {
        prefixSum += num
        val mod = prefixSum % k
        var candidate: Long
        if (mod in modMap) {
            candidate = modMap[mod]!! + prefixSum
        } else {
            candidate = Long.MIN_VALUE
        }
        val dpCurrent = Math.max(dpPrev, candidate)
        val currentValue = dpCurrent - prefixSum
        if (mod in modMap) {
            if (currentValue > modMap[mod]!!) {
                modMap[mod] = currentValue
            }
        } else {
            modMap[mod] = currentValue
        }
        dpPrev = dpCurrent
    }
    return totalSum - dpPrev
}
